using ArcGIS.Core.Data;
using ArcGIS.Core.Geometry;
using NetTopologySuite.Geometries;
using NetTopologySuite.IO;
using NetTopologySuite.Operation.Linemerge;
using S100FC.Topology;
using Xunit.Abstractions;
using IO = System.IO;


namespace TestTopology
{
    public class TestPrecisionModel
    {
        private readonly ITestOutputHelper _output;

        public TestPrecisionModel(ITestOutputHelper output) {
            this._output = output;
            ArcGIS.Core.Hosting.Host.Initialize();

            foreach (var f in System.IO.Directory.GetFiles(AppDomain.CurrentDomain.BaseDirectory, $"*topology*.geodatabase*")) {
                if (IO.Path.GetFileName(f).Equals("topology.geodatabase")) continue;
                System.IO.File.Delete(System.IO.Path.GetFullPath(f));
            }

            var precisionModel = new PrecisionModel(1000000);
            S100FC.Topology.Reloaded.Factory = new GeometryFactory(precisionModel, srid: 4326);

        }

        [Fact]
        public void Test1() {
            using var debugInstance = new Geodatabase(new MobileGeodatabaseConnectionPath(new Uri(IO.Path.GetFullPath("topology.geodatabase"))));

            var spatialReference = SpatialReferenceBuilder.CreateSpatialReference(4326);

            using var polylineFC = debugInstance.OpenDataset<FeatureClass>("main.linestring");
            using var pointFC = debugInstance.OpenDataset<FeatureClass>("main.point");

            using var buffer_linestring = polylineFC.CreateRowBuffer();
            using var buffer_point = pointFC.CreateRowBuffer();

            polylineFC.DeleteRows(new QueryFilter { WhereClause = "1=1" });
            pointFC.DeleteRows(new QueryFilter { WhereClause = "1=1" });

            string[] lineStrings = [lineString_F10800025477, lineString_F10800045667, lineString_F10800053147, lineString_F10500030594, lineString_104, lineString_154, lineString_740, lineString_770];

            var builder = new S100Framework.Topology.Internal.MixedTopologyNetwork(Reloaded.Factory, snapTolerance: Reloaded.Factory.PrecisionModel.GridSize);

            foreach (var lineString in lineStrings) {
                string wkt = lineString.Trim('{', '}');

                var reader = new WKTReader();
                var geometry = (LineString)reader.Read(wkt);

                var sourceId = builder.AddLineString(geometry);
            }


            builder.Build();

            foreach (var sourceId in builder.Sources) {
                var edges = builder.MergeEdgesFor(sourceId);

                var linemerger = new LineMerger();
                linemerger.Add(edges.Select(e => e.Geometry));
                var merged = linemerger.GetMergedLineStrings();

                {
                    foreach (var edge in merged) {
                        buffer_linestring["message"] = $"{sourceId}";

                        buffer_linestring["shape"] = Shared.ConvertToArcGISPolyline((LineString)edge, spatialReference);
                        using var f = polylineFC.CreateRow(buffer_linestring);
                    }
                }
                Assert.Single(merged);
            }


            System.Diagnostics.Debugger.Break();
        }

